beforeExample:
class Example {
    boolean check(String value) {
        return new java.lang.Boolean(value).booleanValue();
    }
    boolean checkAnother(String flag) {
        String data = flag;
        return new java.lang.Boolean(data).booleanValue();
    }
}

afterExample:
class Example {
    boolean check(String value) {
        return java.lang.Boolean.parseBoolean(value);
    }
    boolean checkAnother(String flag) {
        String data = flag;
        return java.lang.Boolean.parseBoolean(data);
    }
}

negativeExample:
class Example {
    java.lang.Boolean createBooleanObject(boolean b) {
        return new java.lang.Boolean(b); // Should not match: not a String argument, no .booleanValue()
    }
    java.lang.Boolean createBooleanFromString(String s) {
        return new java.lang.Boolean(s); // Should not match: no .booleanValue()
    }
    boolean checkPrimitive(String s) {
        return java.lang.Boolean.valueOf(s).booleanValue(); // Should not match: uses valueOf, not new Boolean
    }
}
